PRAGMA foreign_keys=ON;
CREATE TABLE IF NOT EXISTS grups (id INTEGER PRIMARY KEY AUTOINCREMENT, nom TEXT NOT NULL UNIQUE, curs TEXT, descripcio TEXT, created_at TEXT DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS alumnes (id INTEGER PRIMARY KEY AUTOINCREMENT, numero TEXT, grup_id INTEGER REFERENCES grups(id) ON DELETE SET NULL, nom TEXT NOT NULL, cognoms TEXT NOT NULL, data_naixement TEXT, created_at TEXT DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS moduls (id INTEGER PRIMARY KEY AUTOINCREMENT, codi TEXT NOT NULL UNIQUE, nom TEXT NOT NULL, hores INTEGER, curs TEXT, actiu INTEGER DEFAULT 1, descripcio TEXT, created_at TEXT DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS ras (id INTEGER PRIMARY KEY AUTOINCREMENT, modul_id INTEGER NOT NULL REFERENCES moduls(id) ON DELETE CASCADE, codi TEXT NOT NULL, descripcio TEXT NOT NULL, pes REAL DEFAULT 0, nota_minima REAL DEFAULT 5, actiu INTEGER DEFAULT 1, UNIQUE(modul_id,codi));
CREATE TABLE IF NOT EXISTS cas (id INTEGER PRIMARY KEY AUTOINCREMENT, ra_id INTEGER NOT NULL REFERENCES ras(id) ON DELETE CASCADE, codi TEXT NOT NULL, descripcio TEXT NOT NULL, pes REAL DEFAULT 0, actiu INTEGER DEFAULT 1, UNIQUE(ra_id,codi));
CREATE TABLE IF NOT EXISTS tipus_activitat (id INTEGER PRIMARY KEY AUTOINCREMENT, nom TEXT NOT NULL UNIQUE, pes_defecte REAL DEFAULT 0, requereix_minim INTEGER DEFAULT 0, nota_minima REAL DEFAULT 5, limita_ra INTEGER DEFAULT 0, descripcio TEXT, actiu INTEGER DEFAULT 1);
CREATE TABLE IF NOT EXISTS projectes (id INTEGER PRIMARY KEY AUTOINCREMENT, modul_id INTEGER NOT NULL REFERENCES moduls(id) ON DELETE CASCADE, tipus_id INTEGER REFERENCES tipus_activitat(id) ON DELETE SET NULL, nom TEXT NOT NULL, descripcio TEXT, pes_global REAL DEFAULT 0, data_inici TEXT, data_fi TEXT, es_sintesi INTEGER DEFAULT 0, nota_minima REAL DEFAULT 5, created_at TEXT DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS projecte_ra (id INTEGER PRIMARY KEY AUTOINCREMENT, projecte_id INTEGER NOT NULL REFERENCES projectes(id) ON DELETE CASCADE, ra_id INTEGER NOT NULL REFERENCES ras(id) ON DELETE CASCADE, pes REAL DEFAULT 0, UNIQUE(projecte_id,ra_id));
CREATE TABLE IF NOT EXISTS projecte_ca (id INTEGER PRIMARY KEY AUTOINCREMENT, projecte_id INTEGER NOT NULL REFERENCES projectes(id) ON DELETE CASCADE, ca_id INTEGER NOT NULL REFERENCES cas(id) ON DELETE CASCADE, pes REAL DEFAULT 0, UNIQUE(projecte_id,ca_id));
CREATE TABLE IF NOT EXISTS notes_projecte (id INTEGER PRIMARY KEY AUTOINCREMENT, alumne_id INTEGER NOT NULL REFERENCES alumnes(id) ON DELETE CASCADE, projecte_id INTEGER NOT NULL REFERENCES projectes(id) ON DELETE CASCADE, nota REAL NOT NULL CHECK(nota>=0 AND nota<=10), observacions TEXT, updated_at TEXT DEFAULT CURRENT_TIMESTAMP, UNIQUE(alumne_id,projecte_id));
CREATE TABLE IF NOT EXISTS notes_ra_calculades (id INTEGER PRIMARY KEY AUTOINCREMENT, alumne_id INTEGER NOT NULL REFERENCES alumnes(id) ON DELETE CASCADE, ra_id INTEGER NOT NULL REFERENCES ras(id) ON DELETE CASCADE, nota_calculada REAL, nota_final REAL, superat INTEGER, bloquejat_sintesi INTEGER DEFAULT 0, detall TEXT, updated_at TEXT DEFAULT CURRENT_TIMESTAMP, UNIQUE(alumne_id,ra_id));
